  errorParseResponse: { ja: 'AIの応答を正しく読み取れませんでした。もう一度お試しください。', en: 'Could not read the AI response. Please try again.', es: 'No se pudo leer la respuesta de la IA. Intente de nuevo.', fr: 'Impossible de lire la réponse de l\'IA. Veuillez réessayer.', de: 'KI-Antwort konnte nicht gelesen werden. Bitte versuche es erneut.', zh: '无法正确解析AI响应。请再试一次。', ko: 'AI 응답을 올바르게 읽을 수 없습니다. 다시 시도해 주세요.', pt: 'Não foi possível ler a resposta da IA. Por favor, tente novamente.' },
  errorTooLong: { ja: '入力がAPIの上限を超えています。入力を分割して処理してください。', en: 'Input exceeds the API size limit. Please split your input.', es: 'La entrada supera el límite de la API. Divida su entrada.', fr: 'L\'entrée dépasse la limite de l\'API. Veuillez diviser votre entrée.', de: 'Eingabe überschreitet das API-Größenlimit. Bitte teile deine Eingabe auf.', zh: '输入超过API大小限制。请拆分输入。', ko: '입력이 API 크기 제한을 초과합니다. 입력을 분할해 주세요.', pt: 'A entrada excede o limite de tamanho da API. Por favor, divida sua entrada.' },
  errorNetwork: { ja: '通信に失敗しました。ネットワーク接続を確認して再試行してください。', en: 'Network error. Please check your connection and try again.', es: 'Error de red. Verifique su conexión e intente de nuevo.', fr: 'Erreur réseau. Vérifiez votre connexion et réessayez.', de: 'Netzwerkfehler. Bitte überprüfe deine Verbindung und versuche es erneut.', zh: '网络错误。请检查连接后重试。', ko: '네트워크 오류. 연결을 확인한 후 다시 시도해 주세요.', pt: 'Erro de rede. Por favor, verifique sua conexão e tente novamente.' },
