  errorGeneric: { ja: 'エラーが発生しました。再試行してください。', en: 'An error occurred. Please try again.', es: 'Ocurrió un error. Intente de nuevo.', fr: 'Une erreur s\'est produite. Veuillez réessayer.', de: 'Ein Fehler ist aufgetreten. Bitte versuche es erneut.', zh: '发生错误。请重试。', ko: '오류가 발생했습니다. 다시 시도해 주세요.', pt: 'Ocorreu um erro. Por favor, tente novamente.' },
